        CASE
            WHEN I_U_FLG = 'I' THEN 'INSERT'
            WHEN I_U_FLG = 'U' AND TYPE_2_FLG != '2' THEN 'UPDATE'
            WHEN TYPE_2_FLG = '2' THEN 'TYPE_2'
